import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void alreadyPalindrome() {
        assertTrue(new Solution().canBePalindromeRemovingOne("aba"));
    }

    @Test
    void removeOneFromMiddleish() {
        // "abca" → remove 'b' → "aca" palindrome
        assertTrue(new Solution().canBePalindromeRemovingOne("abca"));
    }

    @Test
    void removeOneFromEnd() {
        // "deeee" → remove 'd' → "eeee" palindrome
        assertTrue(new Solution().canBePalindromeRemovingOne("deeee"));
    }

    @Test
    void requireTwoRemovals() {
        assertFalse(new Solution().canBePalindromeRemovingOne("abc"));
    }

    @Test
    void requireTwoRemovalsLonger() {
        assertFalse(new Solution().canBePalindromeRemovingOne("abcdef"));
    }

    @Test
    void emptyString() {
        assertTrue(new Solution().canBePalindromeRemovingOne(""));
    }

    @Test
    void singleChar() {
        assertTrue(new Solution().canBePalindromeRemovingOne("x"));
    }

    @Test
    void twoChars() {
        assertTrue(new Solution().canBePalindromeRemovingOne("ab"));
    }
}
